function QuoteImage({ src, notation }) {
  return (
    <>
        <img src={src} style={{ height: "75%", borderRadius: "20px", margin: "10px"}}/>
        {notation != null && <p style={{marginTop: "0px"}}>{`(${notation})`}</p>}
    </>
  );
}

function SpotifyEmbed({ url }) {
  const regex = /\/track\/([a-zA-Z0-9]+)\?si=/;
  const match = url.match(regex);

  if (match && match.length > 1) {
    const trackId = match[1];

    return (
      <iframe
        className='spotifyembed'
        title="spotify-player"
        src={`https://open.spotify.com/embed/track/${trackId}?utm_source=generator`}
        width="100%"
        height="152"
        frameBorder="0"
        allow="autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture"
        allowFullScreen
        loading="lazy"
        style={{ borderRadius: '25px' }}
      ></iframe>
    );
  } else {
    return <div>Error: Invalid Spotify URL</div>;
  }
}


function ShieldsTile(props) {
  if (props.link === undefined) {
    return (
      <img src={props.shieldslink} alt="" style={{ borderRadius: '20px', height: '35px', padding: '5px' }} />
    );
  } else {
    return (
      <a href={props.link} target="_blank" rel="noreferrer">
        <img src={props.shieldslink} alt="" style={{ borderRadius: '20px', height: '35px', padding: '5px' }} />
      </a>
    );
  }
}


function BlogPost(props) {
  const [isVisible, setIsVisible] = useState(false);

  const toggleVisibility = () => {
    setIsVisible(!isVisible);
  };

  let lines = [];
  let linesText = props.postContent.split('//br');
  linesText.forEach(element => {
    lines.push(
      <span>{element}<br></br></span>
    )
  });
    return (
      <div id="content" style={{ paddingLeft: '2%', paddingRight: '2%', paddingBlock: '1%' }}>
        <h2 onClick={toggleVisibility} style={{ cursor: 'pointer' }}>
          {props.postName}
        </h2>
        {isVisible && (
          <div>
            {lines}
            <br></br>
            {props.imageLink !== undefined && (<img src={props.imageLink} style={{borderRadius: '30px', height: '500px'}}></img>)}
          </div>
        )}
        
      </div>
    );
}



